/*
  assets/bootstrap.used.js
  Minimal, lightweight Bootstrap-like implementations for the components used in this theme:
  - Collapse
  - Modal
  - Tooltip
  - Tab
  - Carousel
  - Dropdown
  - Scrollspy

  Notes:
  - Assumes jQuery is already loaded on the page.
  - This is intentionally small and opinionated; not a full Bootstrap implementation.
  - Use as a drop-in replacement for pages that only rely on these behaviors.
*/
(function($){
  if(typeof $ === 'undefined') return; // jQuery required

  // helpers
  function getSelector($el){
    return $el.attr('data-target') || ($el.attr('href')||'').match(/^#/) ? ($el.attr('data-target') || $el.attr('href')) : null;
  }

  /* Collapse (very small) */
  $(document).on('click','[data-toggle="collapse"]', function(e){
    var $btn = $(this);
    var sel = getSelector($btn);
    if(!sel) return;
    var $target = $(sel);
    if(!$target.length) return;
    var isShown = $target.hasClass('show');
    if(isShown){
      $target.removeClass('show').attr('aria-expanded','false').slideUp(250);
      $btn.addClass('collapsed').attr('aria-expanded','false');
    } else {
      $target.addClass('show').attr('aria-expanded','true').slideDown(250);
      $btn.removeClass('collapsed').attr('aria-expanded','true');
    }
    e.preventDefault();
  });

  /* Modal */
  function showModal($modal){
    if(!$modal || !$modal.length) return;
    var $backdrop = $('<div class="bs-modal-backdrop"></div>').appendTo(document.body);
    $modal.show().addClass('show').attr('aria-hidden','false');
    $('body').addClass('modal-open');
    $backdrop.on('click', function(){ hideModal($modal); });
    $modal.find('[data-dismiss="modal"]').on('click.bsModal', function(e){ e.preventDefault(); hideModal($modal); });
  }
  function hideModal($modal){
    if(!$modal || !$modal.length) return;
    $('.bs-modal-backdrop').remove();
    $modal.removeClass('show').hide().attr('aria-hidden','true');
    $('body').removeClass('modal-open');
    $modal.find('[data-dismiss="modal"]').off('click.bsModal');
  }
  $(document).on('click','[data-toggle="modal"]', function(e){
    var sel = getSelector($(this));
    if(!sel) return;
    var $modal = $(sel);
    if(!$modal.length) return;
    showModal($modal);
    e.preventDefault();
  });

  /* Tooltip (very small) */
  var $tooltipEl = null;
  function showTooltip($el){
    var text = $el.attr('title') || $el.data('original-title') || $el.attr('data-title');
    if(!text) return;
    $el.data('original-title', text).attr('title','');
    $tooltipEl = $('<div class="bs-tooltip" role="tooltip"><div class="arrow"></div><div class="bs-tooltip-inner"></div></div>').appendTo('body');
    $tooltipEl.find('.bs-tooltip-inner').text(text);
    var off = $el.offset();
    var top = off.top - ($tooltipEl.outerHeight() || 30) - 8;
    var left = off.left + ($el.outerWidth()/2) - ($tooltipEl.outerWidth()/2);
    $tooltipEl.css({top: top+'px', left: left+'px', position:'absolute', zIndex: 1070});
  }
  function hideTooltip($el){
    if(!$el) return;
    var orig = $el.data('original-title');
    if(orig!==undefined) $el.attr('title', orig);
    if($tooltipEl) $tooltipEl.remove(), $tooltipEl=null;
  }
  $(document).on('mouseenter','[data-toggle="tooltip"],[data-tooltip="true"]', function(){ showTooltip($(this)); });
  $(document).on('mouseleave','[data-toggle="tooltip"],[data-tooltip="true"]', function(){ hideTooltip($(this)); });
  $(document).on('click','[data-toggle="tooltip"],[data-tooltip="true"]', function(){ hideTooltip($(this)); });

  /* Tabs */
  $(document).on('click','[data-toggle="tab"]', function(e){
    var $a = $(this);
    e.preventDefault();
    var sel = getSelector($a) || $a.attr('href');
    if(!sel) return;
    var $target = $(sel);
    if(!$target.length) return;
    // deactivate siblings
    $a.closest('ul, .nav').find('.active').removeClass('active');
    $a.addClass('active');
    // content
    $target.siblings('.tab-pane').removeClass('active').hide();
    $target.addClass('active').show();
  });

  /* Dropdown (simple) */
  $(document).on('click','[data-toggle="dropdown"]', function(e){
    var $btn = $(this);
    var $menu = $btn.parent().find('.dropdown-menu').first();
    if(!$menu.length) return;
    var isOpen = $menu.hasClass('show');
    $('.dropdown-menu.show').not($menu).removeClass('show').parent().removeClass('show');
    if(isOpen){ $menu.removeClass('show'); $btn.parent().removeClass('show'); }
    else { $menu.addClass('show'); $btn.parent().addClass('show'); }
    e.preventDefault();
    e.stopPropagation();
  });
  $(document).on('click', function(){ $('.dropdown-menu.show').removeClass('show').parent().removeClass('show'); });

  /* Carousel (basic) */
  function initCarousel($el){
    var $inner = $el.find('.carousel-inner').first();
    var $items = $inner.find('.carousel-item');
    var interval = parseInt($el.data('interval')||$el.attr('data-interval')||0,10) || 0;
    var idx = $items.index($inner.find('.carousel-item.active'));
    if(idx<0) idx=0, $items.eq(0).addClass('active');
    var timer = null;
    function next(){
      $items.removeClass('active').hide();
      idx = (idx+1) % $items.length;
      $items.eq(idx).addClass('active').show();
      var $ind = $el.find('.carousel-indicators li');
      if($ind.length){ $ind.removeClass('active').eq(idx).addClass('active'); }
    }
    if(interval>0){ timer = setInterval(next, interval); $el.data('_bs_timer', timer); }
    // indicators
    $el.on('click','[data-slide-to]', function(e){ var to = parseInt($(this).attr('data-slide-to'),10); if(!isNaN(to)){ $items.removeClass('active').hide(); idx=to; $items.eq(idx).addClass('active').show(); $(this).siblings().removeClass('active').end().addClass('active'); } e.preventDefault(); });
    $el.on('slide.bs.carousel', function(){ /* placeholder */ });
  }
  $(document).ready(function(){ $('.carousel[data-ride="carousel"]').each(function(){ initCarousel($(this)); }); });

  /* Scrollspy (naive) */
  function initScrollspy($spy){
    var target = $spy.attr('data-target') || $spy.data('target');
    if(!target) return;
    var $nav = $(target);
    var $links = $nav.find('a[href^="#"]');
    var sections = [];
    $links.each(function(){ var href = $(this).attr('href'); var $sec = $(href); if($sec.length) sections.push({id:href, el:$sec}); });
    function onScroll(){
      var pos = $spy.scrollTop() + 1;
      var activeId = null;
      for(var i=0;i<sections.length;i++){
        var top = sections[i].el.position().top;
        if(pos >= top) activeId = sections[i].id;
      }
      if(activeId){ $links.removeClass('active').filter('[href="'+activeId+'"]').addClass('active'); }
    }
    $spy.on('scroll', onScroll);
    onScroll();
  }
  $(document).ready(function(){ $('[data-spy="scroll"]').each(function(){ initScrollspy($(this)); }); });

  // Simple initializer for tooltip-loaders used in theme.js
  $(document).ready(function(){ $('[data-toggle="tooltip"]').each(function(){ var $t=$(this); if($t.data('init')) return; $t.data('init',true); }); });

})(jQuery);
